import React, { useState, useEffect, useMemo, useRef } from "react";
import {
  restoreSession, login as sbLogin, logout as sbLogout, currentUser,
  loadMyData, saveMyData, updateMyCerts,
  adminListUsers, adminCreateUser, adminDeleteUser, adminUpdatePassword, adminSetActive,
} from "./supabase.js";

/* ============================================================
   ABA 자격증 갱신 연수시간 관리 (geomdan-ceu)
   Supabase Auth + RLS (A방식) · 이수증은 본인만 · 관리자는 계정만 관리
   ============================================================ */

const PK = "#F5A0B1";
const PKL = "#FFF0F3";
const PKD = "#D4728A";
const INK = "#3A2B30";
const MUTE = "#8A7A80";
const LINE = "#F0DDE2";
const OK = "#2E9E6B";
const WARN = "#D98324";
const BAD = "#D4586A";

const LOGO_FULL = "data:image/png;base64,";
const LOGO_SYMBOL = "data:image/png;base64,";
const COPYRIGHT = "© 검단ABA언어행동연구소. All rights reserved.";

const CATS = [
  { key: "ethics", label: "윤리" },
  { key: "superv", label: "수퍼비전" },
  { key: "general", label: "일반" },
];
const catLabel = (k) => CATS.find((c) => c.key === k)?.label || k;

const DEFAULT_CERTS = {
  BCBA: { org: "BACB", cycle: 24, total: 32, req: { ethics: 4, superv: 3, general: 0 },
    note: "수퍼비전 3시간은 RBT·BCaBA·수련생을 감독하는 경우에만 필수. 2027-01-01 이후 시작 주기부터 수퍼비전 4시간으로 상향. CEU는 BACB 승인(ACE) 제공기관 이수분만 인정.", src: "bacb.com BCBA Handbook" },
  "ABAS-1": { org: "한국 KACBA", cycle: 24, total: 32, req: { ethics: 4, superv: 3, general: 0 },
    note: "응용행동분석전문가 1급. 윤리 4시간·수퍼비전 3시간 의무. 한 과목을 윤리·수퍼비전 이중 계산 불가.", src: "abas.co.kr 자격 유지" },
  QBA: { org: "QABA", cycle: 24, total: 32, req: { ethics: 3, superv: 8, general: 0 },
    note: "수퍼비전은 대면/실시간 온라인 25% 이상 수강. 2024-01-01부터 첫 갱신엔 트라우마 케어 2시간·동반질환 2시간 추가.", src: "qababoard.com Renewal" },
  KBA: { org: "한국행동분석학회", cycle: 36, total: 36, req: { ethics: 0, superv: 0, general: 0 },
    note: "3년마다 갱신, 3년간 36시간 이상(50분 단위). 윤리·수퍼비전 세부 의무시간 규정 없음. 갱신 기산일=취득일.", src: "kabac.or.kr 자격 유지 안내" },
};
const CERT_NAMES = Object.keys(DEFAULT_CERTS);

const uid = () => Math.random().toString(36).slice(2, 9);
const todayISO = () => new Date().toISOString().slice(0, 10);

function addMonths(iso, m) {
  if (!iso) return "";
  const d = new Date(iso + "T00:00:00"); if (isNaN(d)) return "";
  const day = d.getDate(); d.setMonth(d.getMonth() + Number(m || 0));
  if (d.getDate() < day) d.setDate(0);
  return d.toISOString().slice(0, 10);
}
function daysBetween(a, b) {
  if (!a || !b) return null;
  return Math.round((new Date(a + "T00:00:00") - new Date(b + "T00:00:00")) / 86400000);
}
function fmtK(iso) {
  if (!iso) return "-";
  const d = new Date(iso + "T00:00:00"); if (isNaN(d)) return iso;
  return `${d.getFullYear()}. ${d.getMonth() + 1}. ${d.getDate()}.`;
}

function blankCert(name) {
  const b = DEFAULT_CERTS[name];
  return { name, org: b.org, acquired: "2020-01-01", cycle: b.cycle, total: b.total, req: { ...b.req }, note: b.note, src: b.src };
}
function blankRecord() { return { id: uid(), title: "", date: todayISO(), appliesTo: {} }; }
function sumForCert(records, name) {
  const s = { ethics: 0, superv: 0, general: 0 };
  records.forEach((r) => { const a = r.appliesTo[name]; if (a) s[a.cat] = (s[a.cat] || 0) + Number(a.hours || 0); });
  return s;
}

// 내 데이터 기본 형태
function emptyData() {
  return { myCerts: [], certs: {}, records: [] };
}
// 보유자격에 맞춰 certs 채우기(없는 건 생성, 있으면 유지)
function ensureCerts(data) {
  const certs = { ...(data.certs || {}) };
  (data.myCerts || []).forEach((n) => { if (!certs[n]) certs[n] = blankCert(n); });
  return { ...data, certs, records: data.records || [] };
}

/* ============================================================
   최상위 App — Supabase Auth 연결
   ============================================================ */
export default function App() {
  const [booting, setBooting] = useState(true);
  const [me, setMe] = useState(null);
  const [data, setData] = useState(null); // { myCerts, certs, records }
  const [screen, setScreen] = useState("login");
  const [activeCert, setActiveCert] = useState(null);
  const saveTimer = useRef(null);

  // 복사 방지
  useEffect(() => {
    const prevent = (e) => e.preventDefault();
    document.addEventListener("contextmenu", prevent);
    document.addEventListener("dragstart", prevent);
    const keyBlock = (e) => {
      if (e.key === "F12") e.preventDefault();
      if ((e.ctrlKey || e.metaKey) && ["u", "s", "p"].includes(e.key.toLowerCase())) e.preventDefault();
    };
    document.addEventListener("keydown", keyBlock);
    return () => {
      document.removeEventListener("contextmenu", prevent);
      document.removeEventListener("dragstart", prevent);
      document.removeEventListener("keydown", keyBlock);
    };
  }, []);

  // 앱 시작 시 세션 복원
  useEffect(() => {
    (async () => {
      const u = await restoreSession();
      if (u) {
        setMe(u);
        const raw = await loadMyData();
        const d = ensureCerts(raw || emptyData());
        setData(d);
        setScreen(d.myCerts.length ? "dashboard" : "pickCerts");
      }
      setBooting(false);
    })();
  }, []);

  // 데이터 변경 시 디바운스 저장
  const persist = (next) => {
    setData(next);
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(() => { saveMyData(next); }, 700);
  };

  const doLogin = async (email, pw) => {
    const res = await sbLogin(email.trim(), pw);
    if (res.error) return res.error;
    const u = currentUser();
    setMe(u);
    const raw = await loadMyData();
    const d = ensureCerts(raw || emptyData());
    setData(d);
    setScreen(d.myCerts.length ? "dashboard" : "pickCerts");
    return null;
  };

  const doLogout = async () => {
    await sbLogout();
    setMe(null); setData(null); setActiveCert(null); setScreen("login");
  };

  const finishPickCerts = (picked) => {
    const d = ensureCerts({ ...(data || emptyData()), myCerts: picked });
    persist(d);
    updateMyCerts(picked); // Auth 캐시(선택)
    setScreen("dashboard");
  };

  const updateCert = (name, patch) => {
    const d = { ...data, certs: { ...data.certs, [name]: { ...data.certs[name], ...patch } } };
    persist(d);
  };
  const setRecords = (updater) => {
    const nextRecords = typeof updater === "function" ? updater(data.records) : updater;
    persist({ ...data, records: nextRecords });
  };

  const goDetail = (name) => { setActiveCert(name); setScreen("detail"); };

  if (booting) {
    return (
      <div style={{ minHeight: "100vh", background: PKL, display: "grid", placeItems: "center", fontFamily: "system-ui" }}>
        <div style={{ color: PKD, fontWeight: 700 }}>불러오는 중…</div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: PKL, color: INK, fontFamily: "'Pretendard','Apple SD Gothic Neo',system-ui,sans-serif" }}>
      <style>{`
        * { box-sizing: border-box; }
        button { font-family: inherit; cursor: pointer; }
        input, select { font-family: inherit; }
        .card { background:#fff; border:1px solid ${LINE}; border-radius:16px; }
        .btn { border:none; border-radius:10px; padding:9px 14px; font-weight:700; font-size:14px; }
        .btn-pk { background:${PK}; color:#fff; }
        .btn-pk:hover { background:${PKD}; }
        .btn-ghost { background:${PKL}; color:${PKD}; border:1px solid ${LINE}; }
        .btn-ghost:hover { background:#fff; }
        .inp { border:1px solid ${LINE}; border-radius:9px; padding:10px 12px; font-size:14px; color:${INK}; outline:none; width:100%; background:#fff; }
        .inp:focus { border-color:${PK}; box-shadow:0 0 0 3px ${PK}22; }
        .lbl { font-size:12px; font-weight:700; color:${MUTE}; margin-bottom:5px; display:block; }
        @keyframes spin { to { transform: rotate(360deg); } }
        body { -webkit-user-select:none; user-select:none; }
        input, textarea { -webkit-user-select:text; user-select:text; }
      `}</style>

      {screen === "login" && <Login onLogin={doLogin} />}

      {me && screen === "pickCerts" && <PickCerts me={me} onDone={finishPickCerts} />}

      {me && screen !== "login" && screen !== "pickCerts" && data && (
        <>
          <TopBar me={me} screen={screen} setScreen={setScreen} logout={doLogout} />
          <main style={{ maxWidth: 980, margin: "0 auto", padding: "20px 16px 40px" }}>
            {screen === "dashboard" && (
              <Dashboard me={{ ...me, myCerts: data.myCerts }} data={data} onOpen={goDetail} />
            )}
            {screen === "detail" && activeCert && data.certs[activeCert] && (
              <Detail cert={data.certs[activeCert]} records={data.records}
                onBack={() => setScreen("dashboard")}
                onChangeCert={(patch) => updateCert(activeCert, patch)}
                setRecords={setRecords} activeCert={activeCert} allMyCerts={data.myCerts} />
            )}
            {screen === "settings" && (
              <Settings myCerts={data.myCerts} onSave={(picked) => finishPickCerts(picked)} />
            )}
            {screen === "admin" && me.role === "admin" && <Admin />}
          </main>
          <Footer />
        </>
      )}
    </div>
  );
}

/* ---------------- 로그인 ---------------- */
function Login({ onLogin }) {
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async () => {
    if (busy) return;
    setBusy(true);
    const e = await onLogin(email, pw);
    setErr(e || "");
    setBusy(false);
  };

  return (
    <div style={{ minHeight: "100vh", display: "grid", placeItems: "center", padding: 20 }}>
      <div style={{ width: "100%", maxWidth: 400 }}>
        <div style={{ textAlign: "center", marginBottom: 22 }}>
          <img src={LOGO_FULL} alt="검단ABA언어행동연구소" style={{ width: 180, height: "auto", margin: "0 auto 6px", display: "block" }} />
          <div style={{ fontSize: 13, color: MUTE, marginTop: 4 }}>자격증 갱신 연수시간(CEU) 관리</div>
        </div>

        <div className="card" style={{ padding: 22 }}>
          <div style={{ marginBottom: 12 }}>
            <label className="lbl">이메일</label>
            <input className="inp" value={email} placeholder="you@example.com" autoComplete="username"
              onChange={(e) => setEmail(e.target.value)} onKeyDown={(e) => e.key === "Enter" && submit()} />
          </div>
          <div style={{ marginBottom: 6 }}>
            <label className="lbl">비밀번호</label>
            <input type="password" className="inp" value={pw} placeholder="비밀번호" autoComplete="new-password"
              onChange={(e) => setPw(e.target.value)} onKeyDown={(e) => e.key === "Enter" && submit()} />
          </div>

          {err && <div style={{ color: BAD, fontSize: 12.5, marginTop: 8 }}>{err}</div>}

          <button className="btn btn-pk" style={{ width: "100%", marginTop: 16, padding: "11px 0", opacity: busy ? 0.6 : 1 }} onClick={submit} disabled={busy}>
            {busy ? "로그인 중…" : "로그인"}
          </button>

          <div style={{ fontSize: 11.5, color: MUTE, marginTop: 14, lineHeight: 1.6, borderTop: `1px solid ${LINE}`, paddingTop: 12 }}>
            계정이 필요하면 연구소 관리자에게 문의하세요.
          </div>
        </div>

        <div style={{ textAlign: "center", fontSize: 11.5, color: MUTE, marginTop: 18 }}>{COPYRIGHT}</div>
      </div>
    </div>
  );
}

/* ---------------- 자격 선택 (첫 로그인) ---------------- */
function PickCerts({ me, onDone }) {
  const [picked, setPicked] = useState([]);
  const toggle = (n) => setPicked((p) => (p.includes(n) ? p.filter((x) => x !== n) : [...p, n]));

  return (
    <div style={{ minHeight: "100vh", display: "grid", placeItems: "center", padding: 20 }}>
      <div style={{ width: "100%", maxWidth: 440 }}>
        <div style={{ textAlign: "center", marginBottom: 18 }}>
          <div style={{ fontWeight: 800, fontSize: 20 }}>{me.name}님, 환영합니다</div>
          <div style={{ fontSize: 13.5, color: MUTE, marginTop: 6 }}>보유하신 자격증을 선택하세요. 선택한 자격만 관리 화면에 표시됩니다.</div>
        </div>
        <div className="card" style={{ padding: 20 }}>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {CERT_NAMES.map((n) => {
              const on = picked.includes(n);
              return (
                <button key={n} onClick={() => toggle(n)} style={{
                  textAlign: "left", border: `1.5px solid ${on ? PK : LINE}`, background: on ? PKL : "#fff",
                  borderRadius: 12, padding: "13px 15px", display: "flex", justifyContent: "space-between", alignItems: "center",
                }}>
                  <div>
                    <div style={{ fontWeight: 800, fontSize: 15.5 }}>{n}</div>
                    <div style={{ fontSize: 12, color: MUTE, marginTop: 2 }}>{DEFAULT_CERTS[n].org} · 갱신 {DEFAULT_CERTS[n].cycle}개월 · {DEFAULT_CERTS[n].total}시간</div>
                  </div>
                  <span style={{ width: 24, height: 24, borderRadius: 7, border: `2px solid ${on ? PK : LINE}`, background: on ? PK : "#fff", color: "#fff", display: "grid", placeItems: "center", fontSize: 15, fontWeight: 800 }}>{on ? "✓" : ""}</span>
                </button>
              );
            })}
          </div>
          <button className="btn btn-pk" style={{ width: "100%", marginTop: 18, padding: "11px 0", opacity: picked.length ? 1 : 0.5 }}
            disabled={!picked.length} onClick={() => onDone(picked)}>시작하기</button>
          <div style={{ fontSize: 11.5, color: MUTE, marginTop: 10, textAlign: "center" }}>나중에 설정에서 언제든 바꿀 수 있어요.</div>
        </div>
      </div>
    </div>
  );
}

/* ---------------- 상단바 ---------------- */
function TopBar({ me, screen, setScreen, logout }) {
  const Tab = ({ id, label }) => (
    <button onClick={() => setScreen(id)} className="btn"
      style={{ background: screen === id ? PK : "transparent", color: screen === id ? "#fff" : INK, padding: "7px 12px" }}>{label}</button>
  );
  return (
    <header style={{ background: "#fff", borderBottom: `1px solid ${LINE}`, padding: "12px 16px", position: "sticky", top: 0, zIndex: 20 }}>
      <div style={{ maxWidth: 980, margin: "0 auto", display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 9, marginRight: "auto" }}>
          <img src={LOGO_SYMBOL} alt="" style={{ width: 34, height: 34, objectFit: "contain" }} />
          <div style={{ fontWeight: 800, fontSize: 15 }}>검단ABA <span style={{ color: MUTE, fontWeight: 600, fontSize: 12.5 }}>연수시간 관리</span></div>
        </div>
        <Tab id="dashboard" label="한눈에 보기" />
        <Tab id="settings" label="설정" />
        {me.role === "admin" && <Tab id="admin" label="관리자" />}
        <span style={{ fontSize: 12.5, color: MUTE, marginLeft: 4 }}>{me.name}</span>
        <button onClick={logout} className="btn btn-ghost" style={{ padding: "7px 11px" }}>로그아웃</button>
      </div>
    </header>
  );
}

function Footer() {
  return <div style={{ textAlign: "center", fontSize: 11.5, color: MUTE, padding: "18px 0 26px" }}>{COPYRIGHT}</div>;
}


function Dashboard({ me, data, onOpen }) {
  const [showHelp, setShowHelp] = useState(true);
  const cards = me.myCerts.map((n) => {
    const cert = data.certs[n];
    const sums = sumForCert(data.records, n);
    const done = sums.ethics + sums.superv + sums.general;
    const pct = cert.total ? Math.min(100, Math.round((done / cert.total) * 100)) : 0;
    const renewal = addMonths(cert.acquired, cert.cycle);
    const dday = daysBetween(renewal, todayISO());
    const lackTotal = Math.max(0, cert.total - done);
    // 항목별 부족
    const lacks = CATS.filter((c) => cert.req[c.key] > 0).map((c) => ({ label: c.label, lack: Math.max(0, cert.req[c.key] - sums[c.key]) }));
    return { n, cert, done, pct, renewal, dday, lackTotal, lacks };
  });

  return (
    <>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end", gap: 10, flexWrap: "wrap" }}>
        <div>
          <div style={{ fontSize: 20, fontWeight: 800 }}>한눈에 보기</div>
          <div style={{ fontSize: 13, color: MUTE, marginTop: 3 }}>보유 자격의 이수 현황과 갱신까지 남은 기간이에요. <b style={{ color: PKD }}>카드를 누르면</b> 이수증 입력·관리 화면으로 이동합니다.</div>
        </div>
        {!showHelp && (
          <button onClick={() => setShowHelp(true)} className="btn btn-ghost" style={{ padding: "6px 12px", fontSize: 12.5 }}>사용법 보기</button>
        )}
      </div>

      {showHelp && (
        <div className="card" style={{ padding: 18, marginBottom: 16, background: PKL, border: `1px solid ${LINE}` }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            <div style={{ fontWeight: 800, fontSize: 15, color: PKD }}>이렇게 사용하세요</div>
            <button onClick={() => setShowHelp(false)} className="btn btn-ghost" style={{ padding: "5px 11px", fontSize: 12.5, background: "#fff" }}>닫기</button>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(210px,1fr))", gap: 12 }}>
            {[
              ["① 자격 카드 열기", "가진 자격 카드를 누르면 상세 화면에서 이수증을 넣고 관리할 수 있어요."],
              ["② 이수증 인식", "이수증 사진을 올리면 강의명·날짜·시간·항목과 인정 자격을 자동으로 읽어줘요. 확인 후 저장하면 끝."],
              ["③ 하나로 여러 자격", "이수증 한 건이 BCBA·QBA처럼 여러 자격에 인정되면 한 번만 등록해도 각 자격에 함께 반영돼요."],
              ["④ 부족분·D-day 확인", "각 카드에서 남은 시간, 항목별 부족분, 갱신까지 남은 날짜(D-day)를 한눈에 볼 수 있어요."],
            ].map(([t, d]) => (
              <div key={t}>
                <div style={{ fontWeight: 700, fontSize: 13.5, marginBottom: 3 }}>{t}</div>
                <div style={{ fontSize: 12.5, color: MUTE, lineHeight: 1.5 }}>{d}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(280px,1fr))", gap: 14 }}>
        {cards.map((c) => {
          let ddBg = OK, ddTxt = `D-${c.dday}`, ddMsg = "여유";
          if (c.dday < 0) { ddBg = BAD; ddTxt = `D+${-c.dday}`; ddMsg = "기한 경과"; }
          else if (c.dday <= 90) { ddBg = BAD; ddMsg = "임박"; }
          else if (c.dday <= 180) { ddBg = WARN; ddMsg = "준비"; }
          const complete = c.done >= c.cert.total && c.lacks.every((l) => l.lack === 0);
          return (
            <button key={c.n} onClick={() => onOpen(c.n)} className="card" style={{ padding: 18, textAlign: "left", cursor: "pointer", border: `1px solid ${LINE}` }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                <div>
                  <div style={{ fontWeight: 800, fontSize: 18 }}>{c.n}</div>
                  <div style={{ fontSize: 12, color: MUTE, marginTop: 2 }}>{c.cert.org}</div>
                </div>
                <span style={{ background: ddBg, color: "#fff", borderRadius: 999, padding: "4px 10px", fontWeight: 800, fontSize: 12.5 }}>{ddTxt}</span>
              </div>

              <div style={{ margin: "14px 0 6px", display: "flex", justifyContent: "space-between", fontSize: 13 }}>
                <span style={{ fontWeight: 700 }}>{c.done} / {c.cert.total} 시간</span>
                <span style={{ color: complete ? OK : PKD, fontWeight: 800 }}>{complete ? "충족 ✓" : `${c.lackTotal}시간 부족`}</span>
              </div>
              <div style={{ height: 10, background: LINE, borderRadius: 999, overflow: "hidden" }}>
                <div style={{ width: `${c.pct}%`, height: "100%", background: complete ? OK : PK }} />
              </div>

              {c.lacks.length > 0 && (
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 12 }}>
                  {c.lacks.map((l) => (
                    <span key={l.label} style={{ fontSize: 11.5, fontWeight: 700, borderRadius: 999, padding: "3px 9px",
                      background: l.lack === 0 ? "#EAF7F0" : "#FDECEE", color: l.lack === 0 ? OK : BAD }}>
                      {l.label} {l.lack === 0 ? "✓" : `-${l.lack}h`}
                    </span>
                  ))}
                </div>
              )}

              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 12 }}>
                <div style={{ fontSize: 12, color: MUTE }}>갱신예정 {fmtK(c.renewal)}</div>
                <span style={{ fontSize: 12, fontWeight: 700, color: PKD }}>이수증 관리 →</span>
              </div>
            </button>
          );
        })}
      </div>
    </>
  );
}

/* ---------------- 자격별 상세 (이수증 관리) ---------------- */
function Detail({ cert, records, onBack, onChangeCert, setRecords, activeCert, allMyCerts }) {
  const renewalDate = useMemo(() => addMonths(cert.acquired, cert.cycle), [cert.acquired, cert.cycle]);
  const dday = useMemo(() => daysBetween(renewalDate, todayISO()), [renewalDate]);
  const sums = useMemo(() => sumForCert(records, cert.name), [records, cert.name]);
  const totalDone = sums.ethics + sums.superv + sums.general;
  const totalPct = cert.total ? Math.min(100, Math.round((totalDone / cert.total) * 100)) : 0;

  return (
    <>
      <button className="btn btn-ghost" onClick={onBack} style={{ marginBottom: 14 }}>← 한눈에 보기</button>

      <div className="card" style={{ padding: 20, marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: 14, alignItems: "flex-start" }}>
          <div>
            <div style={{ fontSize: 22, fontWeight: 800 }}>{cert.name}</div>
            <div style={{ fontSize: 13, color: MUTE, marginTop: 3 }}>{cert.org} · 갱신주기 {cert.cycle}개월 · 필요시간 {cert.total}시간</div>
          </div>
          {dday !== null && (
            <span style={{ background: dday < 0 ? BAD : dday <= 90 ? BAD : dday <= 180 ? WARN : OK, color: "#fff", borderRadius: 999, padding: "5px 13px", fontWeight: 800, fontSize: 15 }}>
              {dday < 0 ? `D+${-dday}` : `D-${dday}`}
            </span>
          )}
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(140px,1fr))", gap: 12, marginTop: 16 }}>
          <div><label className="lbl">현재취득일(직전 갱신)</label>
            <input type="date" className="inp" value={cert.acquired} onChange={(e) => onChangeCert({ acquired: e.target.value })} /></div>
          <div><label className="lbl">갱신주기(개월)</label>
            <input type="number" className="inp" value={cert.cycle} onChange={(e) => onChangeCert({ cycle: Number(e.target.value) })} /></div>
          <div><label className="lbl">이수필요시간</label>
            <input type="number" className="inp" value={cert.total} onChange={(e) => onChangeCert({ total: Number(e.target.value) })} /></div>
          <div><label className="lbl">갱신예정일(자동)</label>
            <div className="inp" style={{ background: PKL, fontWeight: 700, color: PKD }}>{fmtK(renewalDate)}</div></div>
        </div>

        {cert.note && (
          <div style={{ marginTop: 12, fontSize: 12.5, color: WARN, background: "#FFF7EE", border: `1px solid #F5E3CC`, borderRadius: 10, padding: "9px 12px", lineHeight: 1.5 }}>
            ⚠ {cert.note}<span style={{ display: "block", marginTop: 4, color: MUTE, fontSize: 11 }}>근거: {cert.src}</span>
          </div>
        )}

        <div style={{ marginTop: 18 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 6 }}>
            <span style={{ fontWeight: 700 }}>전체 이수</span>
            <span style={{ fontWeight: 800, color: totalDone >= cert.total ? OK : PKD }}>{totalDone} / {cert.total} 시간</span>
          </div>
          <div style={{ height: 12, background: LINE, borderRadius: 999, overflow: "hidden" }}>
            <div style={{ width: `${totalPct}%`, height: "100%", background: totalDone >= cert.total ? OK : PK }} />
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 12, marginTop: 16 }}>
          {CATS.map((c) => {
            const done = sums[c.key], need = Number(cert.req[c.key] || 0), met = done >= need;
            return (
              <div key={c.key} style={{ border: `1px solid ${LINE}`, borderRadius: 12, padding: 14 }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: MUTE, marginBottom: 8 }}>{c.label}</div>
                <div style={{ fontSize: 26, fontWeight: 800, color: met ? OK : INK }}>{done}<span style={{ fontSize: 14, color: MUTE, fontWeight: 600 }}> 시간</span></div>
                <div style={{ fontSize: 12, marginTop: 6, color: met ? OK : BAD, fontWeight: 700 }}>
                  {need > 0 ? (met ? "✓ 요구 충족" : `${Math.max(0, need - done)}시간 부족 (요구 ${need})`) : "요구 없음"}
                </div>
                <div style={{ marginTop: 5 }}>
                  <label className="lbl" style={{ margin: 0, fontSize: 11 }}>최소요구</label>
                  <input type="number" className="inp" style={{ padding: "5px 8px", fontSize: 13 }} value={cert.req[c.key]}
                    onChange={(e) => onChangeCert({ req: { ...cert.req, [c.key]: Number(e.target.value) } })} />
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <RecordManager activeCert={activeCert} records={records} setRecords={setRecords} />
    </>
  );
}

/* ---------------- 이수증 관리 ---------------- */
function RecordManager({ activeCert, records, setRecords }) {
  const [busy, setBusy] = useState(false);
  const [errMsg, setErrMsg] = useState("");
  const [review, setReview] = useState(null);
  const [editing, setEditing] = useState(null);
  const fileRef = useRef(null);

  const saveRecord = (rec) => setRecords((rs) => {
    const i = rs.findIndex((r) => r.id === rec.id);
    if (i >= 0) { const c = [...rs]; c[i] = rec; return c; }
    return [...rs, rec];
  });
  const delRecord = (id) => setRecords((rs) => rs.filter((r) => r.id !== id));
  const visible = records.filter((r) => r.appliesTo[activeCert]);

  const onFile = async (file) => {
    if (!file) return;
    setErrMsg(""); setBusy(true);
    try {
      const b64 = await new Promise((res, rej) => {
        const r = new FileReader();
        r.onload = () => res(String(r.result).split(",")[1]);
        r.onerror = () => rej(new Error("파일을 읽지 못했습니다")); r.readAsDataURL(file);
      });
      const media = file.type && file.type.startsWith("image/") ? file.type : "image/jpeg";
      const prompt = `이 이미지는 ABA 관련 연수·교육 이수증(CEU 증명서)입니다.
자격증 후보: BCBA(BACB), ABAS-1(한국 KACBA), QBA(QABA), KBA(한국행동분석학회). 이수증에 인정 자격 문구가 있으면 그 자격들에 인정됩니다.
다음 JSON만 출력(설명·코드블록 금지): {"title":"강의명","date":"YYYY-MM-DD","applies":[{"cert":"BCBA","hours":숫자,"cat":"ethics|superv|general"}]}
- cat: 윤리=ethics, 수퍼비전=superv, 그 외=general. 인정 자격 못찾으면 applies는 빈 배열. 날짜는 YYYY-MM-DD.`;
      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 1000,
          messages: [{ role: "user", content: [{ type: "image", source: { type: "base64", media_type: media, data: b64 } }, { type: "text", text: prompt }] }] }),
      });
      const data = await resp.json();
      const text = (data.content || []).map((i) => (i.type === "text" ? i.text : "")).join("\n");
      const o = JSON.parse(text.replace(/```json/g, "").replace(/```/g, "").trim());
      const appliesTo = {};
      (Array.isArray(o.applies) ? o.applies : []).forEach((a) => {
        if (CERT_NAMES.includes(a.cert)) appliesTo[a.cert] = { hours: Number(a.hours) || 0, cat: ["ethics", "superv", "general"].includes(a.cat) ? a.cat : "general" };
      });
      if (Object.keys(appliesTo).length === 0) appliesTo[activeCert] = { hours: 0, cat: "general" };
      setReview({ id: uid(), title: String(o.title || "이수 항목"), date: /^\d{4}-\d{2}-\d{2}$/.test(o.date) ? o.date : todayISO(), appliesTo });
    } catch (err) {
      setErrMsg(err.message || "인식에 실패했습니다. 직접 입력해주세요.");
    } finally { setBusy(false); if (fileRef.current) fileRef.current.value = ""; }
  };

  const exportCSV = () => {
    const rows = [["강의명", "날짜", ...CERT_NAMES.flatMap((n) => [`${n} 시간`, `${n} 항목`])]];
    records.forEach((r) => {
      const row = [r.title, r.date];
      CERT_NAMES.forEach((n) => { const a = r.appliesTo[n]; row.push(a ? a.hours : "", a ? catLabel(a.cat) : ""); });
      rows.push(row);
    });
    const csv = "\uFEFF" + rows.map((r) => r.map((v) => `"${String(v).replace(/"/g, '""')}"`).join(",")).join("\n");
    const url = URL.createObjectURL(new Blob([csv], { type: "text/csv;charset=utf-8" }));
    const a = document.createElement("a"); a.href = url; a.download = "이수증_전체.csv"; a.click(); URL.revokeObjectURL(url);
  };

  return (
    <div className="card" style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, marginBottom: 6 }}>
        <div style={{ fontWeight: 800, fontSize: 16 }}>이수증 <span style={{ color: MUTE, fontWeight: 600, fontSize: 13 }}>· {activeCert} 인정 {visible.length}건 / 전체 {records.length}건</span></div>
        <div style={{ display: "flex", gap: 8 }}>
          <button className="btn btn-ghost" onClick={() => fileRef.current?.click()} disabled={busy}>{busy ? "인식 중…" : "📷 이수증 인식"}</button>
          <button className="btn btn-ghost" onClick={() => setEditing(blankRecord())}>+ 직접 추가</button>
          <button className="btn btn-ghost" onClick={exportCSV} disabled={!records.length}>엑셀(CSV)</button>
        </div>
        <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={(e) => onFile(e.target.files?.[0])} />
      </div>
      <div style={{ fontSize: 12, color: MUTE, marginBottom: 14 }}>이수증 한 건이 여러 자격에 인정될 수 있어요. 인정되는 자격을 체크하면 각 자격에 자동 반영됩니다.</div>

      {busy && <div style={{ display: "flex", alignItems: "center", gap: 10, background: PKL, borderRadius: 10, padding: "10px 14px", marginBottom: 12, fontSize: 13, color: PKD }}>
        <span style={{ width: 16, height: 16, border: `2px solid ${PK}`, borderTopColor: "transparent", borderRadius: "50%", display: "inline-block", animation: "spin .8s linear infinite" }} />
        이수증을 읽어 강의명·날짜·시간·항목과 인정 자격을 확인하고 있어요…</div>}
      {errMsg && <div style={{ background: "#FDECEE", border: `1px solid #F5CDD3`, color: BAD, borderRadius: 10, padding: "10px 14px", marginBottom: 12, fontSize: 13 }}>{errMsg}</div>}

      {records.length === 0 ? (
        <div style={{ textAlign: "center", padding: "28px 0", color: MUTE, fontSize: 13.5 }}>아직 이수증이 없습니다. 직접 추가하거나 이수증을 인식해보세요.</div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {records.map((r) => <RecordRow key={r.id} rec={r} activeCert={activeCert} onEdit={() => setEditing(r)} onDelete={() => delRecord(r.id)} />)}
        </div>
      )}

      {review && <RecordEditor title="인식 결과 확인" subtitle="AI가 읽은 내용이에요. 자격·시간·항목을 확인하고 저장하세요."
        rec={review} onCancel={() => setReview(null)} onSave={(rec) => { saveRecord(rec); setReview(null); }} />}
      {editing && <RecordEditor title={records.some((r) => r.id === editing.id) ? "이수증 편집" : "이수증 직접 추가"}
        rec={editing} onCancel={() => setEditing(null)} onSave={(rec) => { saveRecord(rec); setEditing(null); }} />}
    </div>
  );
}

function RecordRow({ rec, activeCert, onEdit, onDelete }) {
  const list = CERT_NAMES.filter((n) => rec.appliesTo[n]);
  return (
    <div style={{ border: `1px solid ${LINE}`, borderRadius: 12, padding: "12px 14px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 10 }}>
        <div style={{ minWidth: 0 }}>
          <div style={{ fontWeight: 700, fontSize: 14.5 }}>{rec.title || "(제목 없음)"}</div>
          <div style={{ fontSize: 12.5, color: MUTE, marginTop: 2 }}>{fmtK(rec.date)}</div>
        </div>
        <div style={{ display: "flex", gap: 6, flexShrink: 0 }}>
          <button onClick={onEdit} className="btn btn-ghost" style={{ padding: "5px 10px", fontSize: 12.5 }}>편집</button>
          <button onClick={onDelete} style={{ border: "none", background: "transparent", color: MUTE, fontSize: 18, lineHeight: 1 }}>×</button>
        </div>
      </div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 8 }}>
        {list.map((n) => {
          const a = rec.appliesTo[n], on = n === activeCert;
          return <span key={n} style={{ fontSize: 12, fontWeight: 700, borderRadius: 999, padding: "3px 10px", background: on ? PK : PKL, color: on ? "#fff" : PKD, border: `1px solid ${on ? PK : LINE}` }}>{n} · {a.hours}h · {catLabel(a.cat)}</span>;
        })}
      </div>
    </div>
  );
}

function RecordEditor({ title, subtitle, rec, onCancel, onSave }) {
  const [draft, setDraft] = useState(() => JSON.parse(JSON.stringify(rec)));
  const set = (patch) => setDraft((d) => ({ ...d, ...patch }));
  const toggleCert = (name) => setDraft((d) => {
    const a = { ...d.appliesTo };
    if (a[name]) delete a[name];
    else { const ex = Object.values(a)[0]; a[name] = ex ? { hours: ex.hours, cat: ex.cat } : { hours: 0, cat: "general" }; }
    return { ...d, appliesTo: a };
  });
  const setField = (name, f, v) => setDraft((d) => ({ ...d, appliesTo: { ...d.appliesTo, [name]: { ...d.appliesTo[name], [f]: v } } }));
  const anyCert = Object.keys(draft.appliesTo).length > 0;

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(58,43,48,.45)", display: "grid", placeItems: "center", padding: 16, zIndex: 50 }} onClick={onCancel}>
      <div className="card" style={{ padding: 20, width: "100%", maxWidth: 480, maxHeight: "88vh", overflowY: "auto" }} onClick={(e) => e.stopPropagation()}>
        <div style={{ fontWeight: 800, fontSize: 17 }}>{title}</div>
        {subtitle && <div style={{ fontSize: 12.5, color: MUTE, marginTop: 3 }}>{subtitle}</div>}
        <div style={{ marginTop: 14 }}><label className="lbl">강의명</label>
          <input className="inp" value={draft.title} placeholder="예: 행동분석 윤리 워크숍" onChange={(e) => set({ title: e.target.value })} /></div>
        <div style={{ marginTop: 12 }}><label className="lbl">날짜</label>
          <input type="date" className="inp" value={draft.date} onChange={(e) => set({ date: e.target.value })} /></div>
        <div style={{ marginTop: 16 }}>
          <label className="lbl">인정되는 자격 (체크한 자격에만 반영)</label>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {CERT_NAMES.map((n) => {
              const on = !!draft.appliesTo[n];
              return (
                <div key={n} style={{ border: `1px solid ${on ? PK : LINE}`, borderRadius: 11, padding: on ? "10px 12px" : "8px 12px", background: on ? PKL : "#fff" }}>
                  <label style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer", fontWeight: 700, fontSize: 14 }}>
                    <input type="checkbox" checked={on} onChange={() => toggleCert(n)} />
                    {n} <span style={{ fontWeight: 600, color: MUTE, fontSize: 12 }}>· {DEFAULT_CERTS[n].org}</span>
                  </label>
                  {on && (
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1.2fr", gap: 8, marginTop: 8 }}>
                      <div><label className="lbl" style={{ fontSize: 11 }}>시간</label>
                        <input type="number" className="inp" style={{ padding: "6px 9px" }} value={draft.appliesTo[n].hours} onChange={(e) => setField(n, "hours", Number(e.target.value))} /></div>
                      <div><label className="lbl" style={{ fontSize: 11 }}>항목</label>
                        <select className="inp" style={{ padding: "6px 9px" }} value={draft.appliesTo[n].cat} onChange={(e) => setField(n, "cat", e.target.value)}>
                          {CATS.map((c) => <option key={c.key} value={c.key}>{c.label}</option>)}
                        </select></div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
        <div style={{ display: "flex", gap: 8, marginTop: 18, justifyContent: "flex-end" }}>
          <button className="btn btn-ghost" onClick={onCancel}>취소</button>
          <button className="btn btn-pk" disabled={!anyCert || !draft.title.trim()} style={{ opacity: !anyCert || !draft.title.trim() ? 0.5 : 1 }} onClick={() => onSave(draft)}>저장</button>
        </div>
        {!anyCert && <div style={{ fontSize: 12, color: BAD, marginTop: 8, textAlign: "right" }}>인정되는 자격을 최소 1개 체크하세요.</div>}
      </div>
    </div>
  );
}


/* ---------------- 설정 (가진 자격 변경) ---------------- */
function Settings({ myCerts, onSave }) {
  const [picked, setPicked] = useState(myCerts || []);
  const toggle = (n) => setPicked((p) => (p.includes(n) ? p.filter((x) => x !== n) : [...p, n]));
  return (
    <div style={{ maxWidth: 480 }}>
      <div style={{ fontSize: 20, fontWeight: 800, marginBottom: 4 }}>설정</div>
      <div style={{ fontSize: 13, color: MUTE, marginBottom: 16 }}>보유 자격을 변경하면 화면에 표시되는 자격이 바뀝니다. 이미 입력한 이수증은 그대로 보존됩니다.</div>
      <div className="card" style={{ padding: 20 }}>
        <label className="lbl">보유 자격증</label>
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {CERT_NAMES.map((n) => {
            const on = picked.includes(n);
            return (
              <button key={n} onClick={() => toggle(n)} style={{ textAlign: "left", border: `1.5px solid ${on ? PK : LINE}`, background: on ? PKL : "#fff", borderRadius: 12, padding: "12px 14px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div><div style={{ fontWeight: 800, fontSize: 15 }}>{n}</div><div style={{ fontSize: 12, color: MUTE, marginTop: 2 }}>{DEFAULT_CERTS[n].org}</div></div>
                <span style={{ width: 22, height: 22, borderRadius: 7, border: `2px solid ${on ? PK : LINE}`, background: on ? PK : "#fff", color: "#fff", display: "grid", placeItems: "center", fontWeight: 800 }}>{on ? "✓" : ""}</span>
              </button>
            );
          })}
        </div>
        <button className="btn btn-pk" style={{ width: "100%", marginTop: 16, opacity: picked.length ? 1 : 0.5 }} disabled={!picked.length} onClick={() => onSave(picked)}>저장</button>
      </div>
    </div>
  );
}

/* ---------------- 관리자 (Supabase 계정 관리) ---------------- */
function Admin() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ email: "", name: "", pw: "" });
  const [msg, setMsg] = useState("");
  const [busy, setBusy] = useState(false);

  const refresh = async () => {
    setLoading(true);
    const res = await adminListUsers();
    if (res.error) setMsg(res.error);
    else setUsers(res.users);
    setLoading(false);
  };
  useEffect(() => { refresh(); }, []);

  const addUser = async () => {
    if (busy) return;
    if (!form.email.trim() || !form.pw.trim()) { setMsg("이메일과 비밀번호를 입력하세요."); return; }
    setBusy(true); setMsg("");
    const res = await adminCreateUser(form.email.trim(), form.pw.trim(), form.name.trim());
    if (res.error) setMsg(res.error);
    else { setForm({ email: "", name: "", pw: "" }); setMsg("계정을 추가했습니다."); await refresh(); }
    setBusy(false);
  };
  const toggleActive = async (u) => {
    setBusy(true);
    const res = await adminSetActive(u.id, !u.is_active);
    if (res.error) setMsg(res.error);
    else await refresh();
    setBusy(false);
  };
  const resetPw = async (u) => {
    const np = prompt(`${u.email}의 새 비밀번호를 입력하세요`);
    if (!np) return;
    setBusy(true);
    const res = await adminUpdatePassword(u.id, np);
    setMsg(res.error || "비밀번호를 변경했습니다.");
    setBusy(false);
  };
  const delUser = async (u) => {
    if (!confirm(`${u.email} 계정을 삭제할까요? 이 사용자의 이수증 데이터도 함께 사라집니다.`)) return;
    setBusy(true);
    const res = await adminDeleteUser(u.id);
    if (res.error) setMsg(res.error);
    else await refresh();
    setBusy(false);
  };

  return (
    <>
      <div style={{ fontSize: 20, fontWeight: 800, marginBottom: 4 }}>관리자</div>
      <div style={{ fontSize: 13, color: MUTE, marginBottom: 16 }}>계정을 발급하고, 사용 여부를 토글로 관리하세요. 각 사용자의 이수증 내용은 관리자도 볼 수 없습니다.</div>

      <div className="card" style={{ padding: 20, marginBottom: 16 }}>
        <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 12 }}>새 계정 발급</div>
        <div style={{ display: "grid", gridTemplateColumns: "1.4fr 1fr 1fr auto", gap: 8, alignItems: "end" }}>
          <div><label className="lbl">이메일(아이디)</label><input className="inp" value={form.email} placeholder="user@geomdan.com" autoComplete="off" onChange={(e) => setForm({ ...form, email: e.target.value })} /></div>
          <div><label className="lbl">이름</label><input className="inp" value={form.name} placeholder="이름" autoComplete="off" onChange={(e) => setForm({ ...form, name: e.target.value })} /></div>
          <div><label className="lbl">비밀번호</label><input className="inp" value={form.pw} placeholder="초기 비밀번호" autoComplete="new-password" onChange={(e) => setForm({ ...form, pw: e.target.value })} /></div>
          <button className="btn btn-pk" style={{ height: 40, opacity: busy ? 0.6 : 1 }} onClick={addUser} disabled={busy}>추가</button>
        </div>
        {msg && <div style={{ fontSize: 12.5, color: PKD, marginTop: 10 }}>{msg}</div>}
      </div>

      <div className="card" style={{ padding: 20 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div style={{ fontWeight: 800, fontSize: 15 }}>사용자 <span style={{ color: MUTE, fontWeight: 600, fontSize: 13 }}>({users.length}명)</span></div>
          <button className="btn btn-ghost" style={{ padding: "5px 11px", fontSize: 12.5 }} onClick={refresh} disabled={busy || loading}>새로고침</button>
        </div>
        {loading ? (
          <div style={{ textAlign: "center", padding: "24px 0", color: MUTE, fontSize: 13 }}>불러오는 중…</div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {users.map((u) => (
              <div key={u.id} style={{ border: `1px solid ${LINE}`, borderRadius: 12, padding: "12px 14px", display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
                <div style={{ minWidth: 0, marginRight: "auto" }}>
                  <div style={{ fontWeight: 700, fontSize: 14 }}>{u.display_name} {u.role === "admin" && <span style={{ fontSize: 11, color: "#fff", background: PKD, borderRadius: 999, padding: "1px 8px", marginLeft: 4 }}>관리자</span>}</div>
                  <div style={{ fontSize: 12, color: MUTE, marginTop: 2 }}>{u.email}</div>
                </div>
                <button onClick={() => toggleActive(u)} disabled={busy} title="사용 여부"
                  style={{ width: 46, height: 26, borderRadius: 999, border: "none", background: u.is_active ? OK : LINE, position: "relative", flexShrink: 0 }}>
                  <span style={{ position: "absolute", top: 3, left: u.is_active ? 23 : 3, width: 20, height: 20, borderRadius: "50%", background: "#fff", transition: "left .15s" }} />
                </button>
                <span style={{ fontSize: 12, color: u.is_active ? OK : MUTE, width: 40 }}>{u.is_active ? "사용중" : "정지"}</span>
                <button className="btn btn-ghost" style={{ padding: "5px 10px", fontSize: 12.5 }} onClick={() => resetPw(u)} disabled={busy}>비번변경</button>
                {u.role !== "admin" && <button onClick={() => delUser(u)} disabled={busy} style={{ border: "none", background: "transparent", color: MUTE, fontSize: 18 }}>×</button>}
              </div>
            ))}
          </div>
        )}
        <div style={{ fontSize: 11.5, color: MUTE, marginTop: 12 }}>토글을 끄면 그 계정은 로그인할 수 없습니다(데이터는 보존).</div>
      </div>
    </>
  );
}
